// Verify WaSender secret + extract the inbound message. Drop non-message events.
const crypto = require('crypto');
const secret = $env.WASENDER_WEBHOOK_SECRET || '';
const item = $input.first().json;
const headers = item.headers || {};
const body = item.body || item;

// Signature check (WaSender sends the secret / HMAC in x-webhook-signature). Lenient: flag, don't hard-block.
const sig = headers['x-webhook-signature'] || headers['X-Webhook-Signature'] || '';
let verified = false;
try {
  const hmac = crypto.createHmac('sha256', secret).update(JSON.stringify(body)).digest('hex');
  verified = Boolean(sig && (sig === secret || sig === hmac));
} catch (e) { verified = false; }

// Find the message across common WaSender shapes.
const ev = body.data || body;
const msg = ev.messages || ev.message || (ev.event === 'messages.upsert' ? ev.data : null) || ev;
const m = Array.isArray(msg) ? msg[0] : msg;
if (!m) return [];

const remoteJid = (m.key && m.key.remoteJid) || m.from || m.chatId || ev.from || '';
if (m.key && m.key.fromMe) return [];           // ignore our own outgoing
if (/status@broadcast|@g\.us/.test(remoteJid)) return [];  // ignore status + groups

const content = m.message || {};
const text = content.conversation
  || (content.extendedTextMessage && content.extendedTextMessage.text)
  || (content.imageMessage && content.imageMessage.caption)
  || m.text || m.body || '';
let type = 'text';
if (content.imageMessage || m.type === 'image') type = 'image';
else if (content.documentMessage) type = 'document';
else if (content.audioMessage) type = 'audio';

return [{ json: {
  message_id: (m.key && m.key.id) || m.id || `${remoteJid}-${m.messageTimestamp || ''}`,
  phone: String(remoteJid).replace(/@s\.whatsapp\.net$/, ''),
  push_name: m.pushName || ev.pushName || '',
  body: text,
  message_type: type,
  media_url: m.mediaUrl || '',
  verified,
  raw: body
}}];

